import { useEffect, useState } from 'react';
import { getAll, remove } from '../services/api';
import { useNavigate } from 'react-router-dom';

function statusClass(s) {
  if (s === 'Pending')           return 'badge badge-pending';
  if (s === 'Processing')        return 'badge badge-processing';
  if (s === 'Verified')          return 'badge badge-verified';
  if (s === 'Passport Generated') return 'badge badge-generated';
  return 'badge badge-rejected';
}

export default function View() {
  const [data, setData]     = useState([]);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => { fetchData(); }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      const res = await getAll();
      setData(res.data);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm(`Delete application #${id}?`)) return;
    await remove(id);
    fetchData();
  };

  const filtered = data.filter(d =>
    d.application_id.toString().includes(search) ||
    d.applicant_id.toString().includes(search)
  );

  return (
    <div className="page">
      <div className="container-lg">
        <div className="page-header">
          <h2>All Applications</h2>
          <div className="divider" />
          <p>{data.length} total record{data.length !== 1 ? 's' : ''} found</p>
        </div>

        <div className="card" style={{ padding: '28px' }}>
          {/* Search */}
          <div className="flex gap-3 items-center justify-between" style={{ marginBottom: 4 }}>
            <div className="search-bar" style={{ flex: 1 }}>
              <svg width="15" height="15" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                <circle cx="11" cy="11" r="8"/><path d="m21 21-4.35-4.35"/>
              </svg>
              <input
                placeholder="Search by Application ID or Applicant ID…"
                onChange={e => setSearch(e.target.value)}
              />
            </div>
            <button className="btn btn-primary btn-sm" onClick={() => navigate('/apply')}>
              + New
            </button>
          </div>

          {/* Table */}
          <div className="table-wrapper">
            <table>
              <thead>
                <tr>
                  <th>App ID</th>
                  <th>Applicant ID</th>
                  <th>Documents</th>
                  <th>Police Verification</th>
                  <th>Status</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {loading ? (
                  <tr><td colSpan={6} className="text-center" style={{ padding: 40, color: 'var(--text-muted)' }}>Loading…</td></tr>
                ) : filtered.length === 0 ? (
                  <tr>
                    <td colSpan={6}>
                      <div className="empty-state">
                        <div className="icon">📭</div>
                        <p>No applications found.</p>
                      </div>
                    </td>
                  </tr>
                ) : (
                  filtered.map(d => (
                    <tr key={d.application_id}>
                      <td><strong>#{d.application_id}</strong></td>
                      <td>{d.applicant_id}</td>
                      <td>
                        <span style={{ color: d.documents_submitted ? 'var(--success)' : 'var(--text-muted)', fontWeight: 500, fontSize: '0.85rem' }}>
                          {d.documents_submitted ? '✓ Yes' : '✗ No'}
                        </span>
                      </td>
                      <td>{d.police_verification}</td>
                      <td><span className={statusClass(d.status)}>{d.status}</span></td>
                      <td>
                        <div className="td-actions">
                          <button
                            className="btn btn-outline btn-sm"
                            onClick={() => navigate(`/update?id=${d.application_id}`)}
                          >
                            Edit
                          </button>
                          <button
                            className="btn btn-danger btn-sm"
                            onClick={() => handleDelete(d.application_id)}
                          >
                            Delete
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
}
